import React, { Component } from "react";
import { Link } from "react-router-dom";
import { motion } from "framer-motion";
import UserProfile from "../Components/UserProfile";
import { useAuth0 } from "@auth0/auth0-react";

function Home() {

  const pdfFile = require("../short photography contract.pdf");
  const {loginWithRedirect, isAuthenticated} = useAuth0();

  function openGallery() {
    window.open("http://localhost:3001/", "_self");
  }

  return (
    <div>
      <div>
        <h1 className="text-black md:text-3xl text-2xl flex justify-center md:m-3 m-8 align-center">
          What are you waiting, book your first session
        </h1>

        <div
          className="items-center align-center gap-3 justify-center md:flex grid-cols-1"
          style={{ height: "25vw" }}
        >
          <div className="flex justify-center align-center md:h-0 h-36">
            <button
              onClick={openGallery}
              className="relative group overflow-hidden px-6 h-12 rounded-full flex space-x-3 items-center duration-500 bg-pink-500 hover:bg-purple-600"
            >
              <span className="relative text-sm text-white">View work</span>
              <div className="flex items-center space-x-3 "></div>
            </button>
          </div>

          <div className="flex justify-center align-center md:h-0 h-6">
            <Link to={isAuthenticated === true ? "/book" : "/login"}>
              <button className="relative group overflow-hidden px-6 h-12 rounded-full flex space-x-3 items-center duration-500 bg-pink-500 hover:bg-purple-600">
                <span className="relative text-sm text-white">Get Started</span>
                <div className="flex items-center -space-x-3 translate-x-3">
                  <div className="w-2.5 h-[1.6px] rounded bg-white origin-left scale-x-0 transition duration-300 group-hover:scale-x-100"></div>
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    className="h-5 w-5 stroke-white -translate-x-2 transition duration-300 group-hover:translate-x-0"
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                    stroke-width="2"
                  >
                    <path
                      stroke-linecap="round"
                      stroke-linejoin="round"
                      d="M9 5l7 7-7 7"
                    />
                  </svg>
                </div>
              </button>
            </Link>
          </div>
        </div>
        <UserProfile />
      </div>
    </div>
  );
}

export default Home;
